        setIsPopUpOpen(true);
        break;
      default:
        setPopUpData({ type: 'success', message: 'Rabisco salvo com sucesso!', duration: 5000 });
        setIsPopUpOpen(true);
    }

    setIsLoading(false);
  };

  /********************************************************************************************************************************
   *                                                         useEffects                                                           *
   ********************************************************************************************************************************/
  useEffect(() => {
    if (!drawInfoToken) {
      setBackdropData({
        title: 'Use o quanto quiser, mas se liga...',
        bodyText: 'Para salvar seu rabisco, é necessário já ter uma conta na plataforma!',
        buttonLabel: 'Depois eu crio, me deixa testar!',
