export function initializePngForExcalidraw(pngUrl) {
  return new Promise((resolve, reject) => {
    fetch(pngUrl)
      .then(response => {
        if (!response.ok) {
          throw new Error(`Network response was not ok: ${response.statusText}`);
        }
        return response.blob();
      })
      .then(blob => {
        const reader = new FileReader();
        reader.onloadend = () => {
          // Construct an Excalidraw element object with the image data
          const imageElement = {
            type: 'image', // specify the element type as image
            version: 2, // Excalidraw internal versioning, may vary
            versionNonce: Date.now(),
            x: 100, // x-coordinate where the image should be placed
            y: 100, // y-coordinate where the image should be placed
            width: 500, // width of the image (you may want to set this dynamically)
            height: 500, // height of the image (you may want to set this dynamically)
            scale: [1, 1], // scale of the image (1 means no scaling)
            isDeleted: false,
            fillStyle: 'hachure', // the fill style of the image
            strokeWidth: 1, // the width of the stroke
            strokeStyle: 'solid', // the style of the stroke
            roughness: 1, // the roughness of the drawing
            opacity: 100, // the opacity of the image
            groupIds: [], // groups this element belongs to
            strokeColor: '#000000', // stroke color
            backgroundColor: 'transparent', // background color
            strokeSharpness: 'sharp', // the sharpness of the stroke
            seed: Date.now(), // random seed for Excalidraw's internal use
            src: reader.result, // the base64 encoded image source,
          };

          resolve([imageElement]); // Resolve with an array containing our image element
